public class Package
{
  private int myLength;
  private int myWidth;
  private int myHeight;
  private double myWeight;
  private String myDestination;
  public Package()
  {
    myLength = 0;
    myWidth = 0;
    myHeight = 0;
    myWeight = 0;
    myDestination = "none";
  }
  public Package(int len, int wid, int h, double wt, String dest)
  {
    myLength = len;
    myWidth = wid;
    myHeight = h;
    myWeight = wt;
    myDestination = dest;
  }
  public int getLength()
  {
    return myLength;
  }
  public int getWidth()
  {
    return myWidth;
  }
  public int getHeight()
  {
    return myHeight;
  }
  public double getWeight()
  {
    return myWeight;
  }
  public String getDestination()
  {
    return myDestination;
  }
  public void setWeight(double weig)
  {
    myWeight = weig;
  }
  public void setDestination(String newDest)
  {
    myDestination = newDest;
  }
  public int getGirth()
  {
    int ans = getLength() + getWidth();
    return ans;
  }
  public double getCost(int rate)
  {
    double ans = getWeight() * (getGirth() + getLength());
    return 1.5 * rate;
  }
}
